# E2-Skeptic three-route assess for S46-T1-A-E2
def assess(record: dict) -> str:
    required = {'window_end', 'watermark', 'event_time', 'allowed_lateness', 'case_id'}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    try:
        ok = not (record["event_time"] > record["window_end"] or record["event_time"] < record["watermark"] - record["allowed_lateness"])
    except Exception:
        return 'SIDE_OUTPUT_LATE_EVENT'
    return 'PASS' if ok else 'SIDE_OUTPUT_LATE_EVENT'

record = {"case_id": "CASO-HYO-046-1A", **{"event_time":110,"window_end":120,"watermark":115,"allowed_lateness":10}}
valid = dict(record)
invalid = dict(valid)
# adverse: invert first boolean flag if any
_flipped=False
for _k,_v in list(invalid.items()):
    if isinstance(_v,bool):
        invalid[_k]= (not _v)
        _flipped=True
        break
if not _flipped and isinstance(invalid.get('stages'), list):
    invalid['stages']=list(reversed(invalid['stages']))
elif not _flipped and 'dependencies' in invalid:
    invalid['dependencies']=[["domain","infrastructure"]]
incomplete={k:v for k,v in valid.items() if k != 'allowed_lateness'}
print(assess(valid), assess(invalid), assess(incomplete))

